// Score each order 0-100 from simple heuristics
return $input.all().map(item => {
  const j = item.json;
  let score = 50;
  if (j.email) score += 20;
  if (j.total) score += 15;
  if ((j.source || '') === 'referral') score += 15;
  return { json: { ...j, score: Math.min(100, score) } };
});
